/**
 * @fileoverview Divider barrel.
 * @module module/Divider
 */
import { default as razyui } from '../index.js';
import { DividerDef as DEF } from './Divider.def.js';
import Divider from './Divider/index.js';

razyui.Divider = Divider;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Divider);
}

export default Divider;

export const stylesheet = null;
