/**
 * @fileoverview Divider component logic.
 * @module module/Divider/index
 */

import { default as razyui } from '../../index.js';
import { DEFAULTS } from './constants.js';
import { setupDOM } from './view.js';

const Divider = class {
    #root   = null;
    #config = {};

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Divider: element not found \u2192', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        setupDOM(root, this.#config);
    }

    get element() { return this.#root[0]; }
};

export default Divider;
