/**
 * @fileoverview Divider constants.
 * @module module/Divider/constants
 */

import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:      'divider',
    SOFT:      'is-soft',
    HAS_LABEL: 'has-label',
    LABEL_LEFT:  'label-left',
    LABEL_RIGHT: 'label-right',
});

export const DEFAULTS = Object.freeze({
    vertical:   false,
    label:      null,
    labelAlign: 'center',
});

export const PART = defineParts('Divider', {
    ROOT:     { class: 'divider-root', aliases: ['root', 'divider', 'hr'] },
    VERTICAL: { class: 'divider-vertical', aliases: ['vertical'] },
    LABELED:  { class: 'divider-labeled', aliases: ['labeled', 'with-label'] },
    LABEL:    { class: 'divider-label', aliases: ['label', 'text'], tag: 'span' },
    LINE:     { class: 'divider-line', aliases: ['line', 'rule'], tag: 'span' },
});

PART.ROOT.jit     = 'w-full [height:var(--dv-weight)] bg-[var(--dv-color)] [border:none] my-[var(--dv-my)] {is-soft}:opacity-50';
PART.VERTICAL.jit = '[width:var(--dv-weight)] self-stretch bg-[var(--dv-color)] [border:none] my-0 mx-[var(--dv-my)]';
PART.LABELED.jit  = 'flex items-center gap-[var(--dv-label-gap)] w-full [border:none] my-[var(--dv-my)] {is-soft}:opacity-50';
PART.LABEL.jit    = 'shrink-0 text-[var(--dv-label-size)] fg-[var(--dv-label-color)] [white-space:nowrap]';
PART.LINE.jit     = 'flex-1 [height:var(--dv-weight)] bg-[var(--dv-color)]';
