/**
 * @fileoverview Divider view setup.
 * @module module/Divider/view
 */

import { CLS, PART } from './constants.js';

export function setupDOM(root, config) {
    const { vertical, label, labelAlign } = config;
    const el = root[0];

    root.addClass(CLS.ROOT);
    el.setAttribute('role', 'separator');

    // Detect label from config or existing inner content
    const labelText = label || el.textContent.trim() || null;

    if (labelText) {
        // --- Labeled divider ---
        el.textContent = '';

        root.addClass(CLS.HAS_LABEL);
        PART.LABELED.apply(root);
        el.setAttribute('aria-label', labelText);

        if (labelAlign === 'left')  root.addClass(CLS.LABEL_LEFT);
        if (labelAlign === 'right') root.addClass(CLS.LABEL_RIGHT);

        // First line segment
        const $line1 = PART.LINE.create();
        if (labelAlign === 'left') {
            $line1[0].style.flex = '0 0 auto';
            $line1[0].style.width = 'var(--dv-line-min)';
        }
        root.append($line1);

        // Label
        const $label = PART.LABEL.create();
        $label.text(labelText);
        root.append($label);

        // Second line segment
        const $line2 = PART.LINE.create();
        if (labelAlign === 'right') {
            $line2[0].style.flex = '0 0 auto';
            $line2[0].style.width = 'var(--dv-line-min)';
        }
        root.append($line2);
    } else if (vertical) {
        // --- Vertical divider ---
        PART.ROOT.apply(root);
        PART.VERTICAL.apply(root);
        el.setAttribute('aria-orientation', 'vertical');
    } else {
        // --- Plain horizontal divider ---
        PART.ROOT.apply(root);
    }

    return {};
}
